CREATE TABLE tasks (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, priority TEXT NOT NULL, status TEXT NOT NULL, assigned_to TEXT NOT NULL, due_date DATE NOT NULL);
CREATE TABLE leads (id INTEGER PRIMARY KEY AUTOINCREMENT, client_name TEXT NOT NULL, source TEXT NOT NULL, lead_stage TEXT NOT NULL, conversion_probability REAL NOT NULL, last_contacted DATE NOT NULL);
CREATE TABLE notes (id INTEGER PRIMARY KEY AUTOINCREMENT, content TEXT NOT NULL, category TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE content_items (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, platform TEXT NOT NULL, campaign TEXT NOT NULL, planned_date DATE NOT NULL, scheduled_at TEXT NOT NULL, status TEXT NOT NULL, media_asset_url TEXT NOT NULL, canva_reference TEXT NOT NULL, video_topic TEXT, hashtags TEXT NOT NULL, cta TEXT NOT NULL, views INTEGER DEFAULT 0, engagement INTEGER DEFAULT 0, leads_generated INTEGER DEFAULT 0, conversion_source TEXT NOT NULL);
CREATE TABLE activity_events (id INTEGER PRIMARY KEY AUTOINCREMENT, event_type TEXT NOT NULL, entity_type TEXT NOT NULL, entity_id TEXT NOT NULL, summary TEXT NOT NULL, actor TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE notifications (id INTEGER PRIMARY KEY AUTOINCREMENT, category TEXT NOT NULL, title TEXT NOT NULL, message TEXT NOT NULL, is_read BOOLEAN DEFAULT 0, due_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE lead_attributions (id INTEGER PRIMARY KEY AUTOINCREMENT, lead_id INTEGER NOT NULL, content_item_id INTEGER, platform TEXT NOT NULL, campaign TEXT NOT NULL, conversion_path TEXT NOT NULL, is_whatsapp_originated BOOLEAN DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE whatsapp_intakes (id INTEGER PRIMARY KEY AUTOINCREMENT, contact_name TEXT NOT NULL, phone TEXT NOT NULL, inquiry TEXT NOT NULL, tags TEXT NOT NULL, consultation_requested BOOLEAN DEFAULT 0, followup_prepared BOOLEAN DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE seo_engineering_requests (id INTEGER PRIMARY KEY AUTOINCREMENT, business_objective TEXT NOT NULL, seo_issue TEXT NOT NULL, technical_requirements TEXT NOT NULL, priority TEXT NOT NULL, expected_impact TEXT NOT NULL, assigned_developer TEXT NOT NULL, implementation_status TEXT NOT NULL);
CREATE TABLE engineering_updates (id INTEGER PRIMARY KEY AUTOINCREMENT, request_id INTEGER NOT NULL, comment TEXT NOT NULL, implementation_log TEXT NOT NULL, deployment_status TEXT NOT NULL, blockers TEXT, priority_score INTEGER NOT NULL, timeline_eta TEXT NOT NULL);
CREATE TABLE seo_automation_runs (id INTEGER PRIMARY KEY AUTOINCREMENT, metadata_audit_issues INTEGER DEFAULT 0, internal_link_suggestions INTEGER DEFAULT 0, duplicate_metadata_found INTEGER DEFAULT 0, schema_validation_failures INTEGER DEFAULT 0, broken_links_found INTEGER DEFAULT 0, optimization_score REAL DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE weekly_seo_reports (id INTEGER PRIMARY KEY AUTOINCREMENT, week_label TEXT NOT NULL UNIQUE, organic_traffic INTEGER NOT NULL, consultation_conversions INTEGER NOT NULL, leads_generated INTEGER NOT NULL, weekly_growth_pct REAL NOT NULL, executive_summary TEXT NOT NULL);
